import boto3
import cfnresponse

logs = boto3.client('logs')
appsync = boto3.client('appsync')

# Log group names to skip even if they match the prefix filter.
# Step Functions retention is managed by its own CFN template (14 days).
SKIP_PREFIXES = (
    '/aws/stepfunction/team-step-function/',
)


def _iter_log_groups(prefix):
    paginator = logs.get_paginator('describe_log_groups')
    for page in paginator.paginate(logGroupNamePrefix=prefix):
        for lg in page.get('logGroups', []):
            yield lg


def _team_lambda_log_groups(env):
    suffix = '-' + env
    for lg in _iter_log_groups('/aws/lambda/'):
        name = lg['logGroupName']
        # Match Amplify-created Lambda log groups for this TEAM env only:
        # /aws/lambda/<funcName>-<env>
        short = name[len('/aws/lambda/'):]
        if (short.startswith('team') or short.startswith('Team')) and short.endswith(suffix):
            yield name


def _team_appsync_log_groups(env):
    api_name = 'team-' + env
    api_ids = []
    next_token = None
    while True:
        kwargs = {'maxResults': 25}
        if next_token:
            kwargs['nextToken'] = next_token
        resp = appsync.list_graphql_apis(**kwargs)
        for api in resp.get('graphqlApis', []):
            if api.get('name') == api_name:
                api_ids.append(api['apiId'])
        next_token = resp.get('nextToken')
        if not next_token:
            break
    for api_id in api_ids:
        prefix = '/aws/appsync/apis/' + api_id
        # exact log group is /aws/appsync/apis/<apiId>
        for lg in _iter_log_groups(prefix):
            yield lg['logGroupName']


def _apply(retention_days, env):
    applied = []
    for name in _team_lambda_log_groups(env):
        if any(name.startswith(p) for p in SKIP_PREFIXES):
            continue
        logs.put_retention_policy(logGroupName=name, retentionInDays=retention_days)
        applied.append(name)
    for name in _team_appsync_log_groups(env):
        logs.put_retention_policy(logGroupName=name, retentionInDays=retention_days)
        applied.append(name)
    return applied


def handler(event, context):
    try:
        if event.get('RequestType') == 'Delete':
            cfnresponse.send(event, context, cfnresponse.SUCCESS, {'Data': 'Delete: noop'})
            return

        props = event.get('ResourceProperties', {}) or {}
        retention_days = int(props.get('retentionDays', 90))
        env = props.get('env', '')

        applied = _apply(retention_days, env)
        print('Applied retention {} days to {} log groups'.format(retention_days, len(applied)))
        for n in applied:
            print('  - ' + n)

        cfnresponse.send(
            event,
            context,
            cfnresponse.SUCCESS,
            {'Count': len(applied), 'RetentionDays': retention_days},
        )
    except Exception as e:
        print('Error: {}'.format(e))
        cfnresponse.send(event, context, cfnresponse.FAILED, {'Error': str(e)})
